from typing import TypedDict

class SecureState(TypedDict):
    user_id: str
    auth_context: dict  # Immutable
    config: dict

@graph.node
def auth_guard(state: SecureState) -> SecureState:
    user_id = state['config']['configurable'].get('user_id')
    if state['user_id'] != user_id:
        raise PermissionError(f"User mismatch: {state['user_id']} != {user_id}")

    # Freeze auth context
    state['auth_context'] = {
        **state['auth_context'],
        'frozen': True,
        'validated_at': '2024-01-01T00:00:00Z'
    }
    return state

graph.add_node("auth_guard", auth_guard)
graph.set_entry_point("auth_guard")

from typing import Annotated, TypedDict
import operator
from langgraph.graph import StateGraph

def validate_user_token(user_id: str, token: str) -> bool:
    return user_id.startswith(token[:8])  # Simplified check

class AuthenticatedState(TypedDict):
    user_id: str
    messages: Annotated[list, add_messages]
    auth_token: str

    def __setitem__(self, key, value):
        if key == 'auth_token':
            if not validate_user_token(self['user_id'], value):
                raise PermissionError("Invalid auth token")
        super().__setitem__(key, value)

# Use in graph
workflow = StateGraph(AuthenticatedState)

@workflow.node
def secure_tool(state: AuthenticatedState):
    # Token automatically validated on state mutation
    return {"messages": [{"role": "tool", "content": "Secure execution"}]}

from langgraph.prebuilt import ToolNode, tools_condition
from langgraph.graph import StateGraph

class BranchState(TypedDict):
    user_id: str
    branch_tokens: dict[str, str]  # Per-branch tokens
    results: dict[str, dict]

@graph.node
def branch_auth(state: BranchState):
    branches = ['read', 'write', 'admin']
    state['branch_tokens'] = {
        b: f"token_{state['user_id']}_{b}" for b in branches
        if b in state.get('permissions', [])
    }
    return state

graph.add_node("branch_auth", branch_auth)

# Parallel execution respects branch tokens
@graph.node
def read_branch(state):
    token = state['branch_tokens'].get('read')
    if not token:
        return {"results": {"read": "PERMISSION_DENIED"}}
    return {"results": {"read": "success"}}

graph.add_node("read_branch", read_branch)
